mapper.select:
SELECT s.id, s.order_no, s.org_id, s.grain_id, s.position_id, s.plan_weight, s.actual_out_weight, s.ref_price, s.actual_price, s.total_amount, s.actual_amount, s.received_amount, (COALESCE(s.total_amount, 0) - COALESCE(s.received_amount, 0)) AS unreceived_amount, s.reserved_stock, s.status, s.out_status, s.payment_status, s.void_reason, s.attachment_url, s.audit_user_id, s.audit_time, s.create_user_id, s.create_time, s.update_time, o.org_name, g.grain_type, g.grain_grade, p.position_name, au.real_name AS audit_user_name, cu.real_name AS create_user_name, CASE s.status WHEN 0 THEN '草稿' WHEN 1 THEN '待审核' WHEN 2 THEN '待出库' WHEN 3 THEN '部分出库' WHEN 4 THEN '已出库' WHEN 5 THEN '已完成' WHEN 6 THEN '已驳回' WHEN 7 THEN '已作废' ELSE '未知' END AS status_name, CASE s.out_status WHEN 0 THEN '未出库' WHEN 1 THEN '部分出库' WHEN 2 THEN '已出库' ELSE '未知' END AS out_status_name, CASE s.payment_status WHEN 0 THEN '未收款' WHEN 1 THEN '部分收款' WHEN 2 THEN '已收款' ELSE '未知' END AS payment_status_name FROM t_sales_order s INNER JOIN t_downstream_org o ON s.org_id = o.id INNER JOIN t_grain g ON s.grain_id = g.id INNER JOIN t_storage_position p ON s.position_id = p.id LEFT JOIN t_user au ON s.audit_user_id = au.id LEFT JOIN t_user cu ON s.create_user_id = cu.id WHERE 1=1
AND (s.order_no LIKE CONCAT('%', #{keyword}, '%') OR o.org_name LIKE CONCAT('%', #{keyword}, '%'))
AND s.org_id = #{orgId}
AND s.grain_id = #{grainId}
AND s.status = #{status}
AND s.payment_status = #{paymentStatus}
ORDER BY s.create_time DESC
